CREATE INDEX `idx_project_assignments_project` ON `project_assignments` (`project_id`);
CREATE UNIQUE INDEX `idx_project_assignments_user_project` ON `project_assignments` (`user_id`,`project_id`);

ALTER TABLE `test_runs` ADD `did_not_run_tests` integer DEFAULT 0 NOT NULL;

CREATE TABLE `failure_cluster_aliases` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`project_id` integer NOT NULL,
	`fingerprint` text NOT NULL,
	`cluster_id` integer NOT NULL,
	`created_at` integer NOT NULL,
	FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`cluster_id`) REFERENCES `failure_clusters`(`id`) ON UPDATE no action ON DELETE cascade
);

CREATE UNIQUE INDEX `idx_failure_cluster_aliases_project_fingerprint` ON `failure_cluster_aliases` (`project_id`,`fingerprint`);
CREATE INDEX `idx_failure_cluster_aliases_cluster` ON `failure_cluster_aliases` (`cluster_id`);
ALTER TABLE `failure_clusters` ADD `embedding` text;
ALTER TABLE `failure_clusters` ADD `embedding_model` text;

CREATE TABLE `cluster_merge_suggestions` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`project_id` integer NOT NULL,
	`cluster_a_id` integer NOT NULL,
	`cluster_b_id` integer NOT NULL,
	`score` real,
	`method` text NOT NULL,
	`llm_confidence` text,
	`llm_reason` text,
	`status` text DEFAULT 'pending' NOT NULL,
	`created_at` integer NOT NULL,
	`updated_at` integer NOT NULL,
	FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`cluster_a_id`) REFERENCES `failure_clusters`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`cluster_b_id`) REFERENCES `failure_clusters`(`id`) ON UPDATE no action ON DELETE cascade
);

CREATE UNIQUE INDEX `idx_cluster_merge_suggestions_pair` ON `cluster_merge_suggestions` (`cluster_a_id`,`cluster_b_id`);
CREATE INDEX `idx_cluster_merge_suggestions_project_status` ON `cluster_merge_suggestions` (`project_id`,`status`);

ALTER TABLE `failure_clusters` ADD `title` text;

ALTER TABLE `test_runs_cases` ADD `wasted_time_ms` integer;

CREATE TABLE `locator_snapshots` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`test_case_id` integer NOT NULL,
	`location` text NOT NULL,
	`used_method` text NOT NULL,
	`used_args` text NOT NULL,
	`used_args_fp` text NOT NULL,
	`element_tag` text,
	`element_attrs` text NOT NULL,
	`element_text` text,
	`alternatives` text NOT NULL,
	`last_seen_run_id` integer,
	`last_seen_at` integer NOT NULL,
	FOREIGN KEY (`test_case_id`) REFERENCES `test_cases`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`last_seen_run_id`) REFERENCES `test_runs`(`id`) ON UPDATE no action ON DELETE set null
);

CREATE UNIQUE INDEX `idx_locator_snapshots_location` ON `locator_snapshots` (`test_case_id`,`location`);
CREATE INDEX `idx_locator_snapshots_fp` ON `locator_snapshots` (`test_case_id`,`used_method`,`used_args_fp`);

CREATE INDEX `idx_locator_snapshots_args_fp` ON `locator_snapshots` (`used_args_fp`);

ALTER TABLE `test_runs` ADD `reporter_version` text;

ALTER TABLE `files` ADD `metadata` text;

ALTER TABLE `test_runs_cases` ADD `page_state` text;

PRAGMA foreign_keys=OFF;
CREATE TABLE `__new_failure_diagnoses` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`cluster_id` integer,
	`scope` text DEFAULT 'cluster' NOT NULL,
	`test_runs_case_id` integer,
	`context_sha` text,
	`status` text DEFAULT 'running' NOT NULL,
	`provider` text,
	`model` text,
	`category` text,
	`confidence` text,
	`summary` text,
	`root_cause` text,
	`details` text,
	`error` text,
	`input_tokens` integer,
	`output_tokens` integer,
	`duration_ms` integer,
	`feedback` text,
	`feedback_note` text,
	`created_at` integer NOT NULL,
	`updated_at` integer NOT NULL,
	FOREIGN KEY (`cluster_id`) REFERENCES `failure_clusters`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`test_runs_case_id`) REFERENCES `test_runs_cases`(`id`) ON UPDATE no action ON DELETE cascade
);

DROP TABLE `failure_diagnoses`;
ALTER TABLE `__new_failure_diagnoses` RENAME TO `failure_diagnoses`;
PRAGMA foreign_keys=ON;
CREATE UNIQUE INDEX `idx_failure_diagnoses_cluster_scope` ON `failure_diagnoses` (`cluster_id`,`scope`);
